<script setup>
import gsap from 'gsap'

function float(elId, yVal) {
  return gsap.to(elId, { y: yVal, duration: 2, repeat: -1, yoyo: true, ease: 'sine.inOut' })
}

onMounted(() => {
  gsap.set('#arw-top', { opacity: 0 })
  gsap.set('#arw-mid', { opacity: 0 })
  gsap.set('#arw-btm', { opacity: 0 })
  gsap.set('#db-dot', { fill: '#e06c70' })

  float('#form', 50)
  float('#lock', -30)
  float('#db-object', -20)
  const arwTl = gsap.timeline({ repeat: -1, repeatDelay: 0.4 })

  arwTl
    .set(['#arw-top', '#arw-mid', '#arw-btm'], { autoAlpha: 0 })
    .to('#arw-top', { autoAlpha: 1, duration: 0.35 })
    .to('#arw-mid', { autoAlpha: 1, duration: 0.35 })
    .to('#db-dot', { fill: '#b0d84b', duration: 0.35 })
    .to('#arw-btm', { autoAlpha: 1, duration: 0.35 }, '-<0.35')
    .to(['#arw-top', '#arw-mid', '#arw-btm'], {
      autoAlpha: 0,
      duration: 0.3,
      delay: 0.4,
    })
})
</script>

